import "./globals.css";

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="fr">
      <body>{children}</body>
    </html>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

"use client";

import { useForm } from "react-hook-form";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { signIn } from "next-auth/react";

const schema = z.object({ email: z.string().email().max(255), password: z.string().min(8).max(128) });

export default function LoginPage() {
  const { register, handleSubmit, setError, formState } = useForm<z.infer<typeof schema>>({ resolver: zodResolver(schema) });
  const onSubmit = handleSubmit(async (values) => {
    const result = await signIn("credentials", { ...values, redirect: false });
    if (result?.error) setError("root", { message: "Identifiants incorrects" });
    if (!result?.error) window.location.assign("/");
  });
  return <form onSubmit={onSubmit}><input placeholder="Email" {...register("email")} /><input type="password" placeholder="Mot de passe" {...register("password")} /><button type="submit">Se connecter</button>{formState.errors.root?.message}</form>;
}

import { auth } from "@/lib/auth";
import Sidebar from "@/components/layout/Sidebar";
import Topbar from "@/components/layout/Topbar";

export default async function AppLayout({ children }: { children: React.ReactNode }) {
  const session = await auth();
  return <div className="min-h-screen grid grid-cols-[240px_1fr]"><Sidebar /><div><Topbar companyName={session?.user.company_id ?? ""} />{children}</div></div>;
}

import { auth } from "@/lib/auth";
import { redirect } from "next/navigation";

export default async function DashboardPage() {
  const session = await auth();
  if (!session?.user?.company_id) {
    redirect("/login");
  }

  return (
    <section>
      <h1>Tableau de bord — Bienvenue</h1>
      <p>Aucune donnée à afficher pour le moment.</p>
    </section>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

export default function NavItem({ href, label }: { href: string; label: string }) {
  const pathname = usePathname();
  const active = pathname === href || (href !== "/" && pathname.startsWith(href));
  return <Link href={href} className={active ? "font-semibold" : "font-normal"}>{label}</Link>;
}

import NavItem from "@/components/layout/NavItem";

export default function Sidebar() {
  return <aside><NavItem href="/" label="Tableau de bord" /><NavItem href="/documents" label="Documents" /><NavItem href="/observations" label="Observations" /><NavItem href="/conflicts" label="Conflits" /><NavItem href="/reports" label="Rapports" /><NavItem href="/chat" label="Chat" /><NavItem href="/settings" label="Paramètres" /></aside>;
}

"use client";

import { signOut } from "next-auth/react";

export default function Topbar({ companyName }: { companyName: string }) {
  return <header><span>{companyName}</span><button type="button" onClick={() => signOut({ callbackUrl: "/login" })}>Se déconnecter</button></header>;
}

export const LOW_CONFIDENCE_THRESHOLD = 0.70;

export const AUTH_JWT_SHAPE = {
  user_id: "string",
  company_id: "string",
  role: "admin | editor | viewer",
} as const;

export const QUEUE_NAMES = {
  OCR: "ocr-job",
  EMBEDDING: "embedding-job",
  EXTRACTION: "extraction-job",
  SEMANTIC_CONFLICT: "semantic-conflict-job",
  RENDER_PDF: "render-pdf-job",
  PENDING_OBS_TIMEOUT: "pending-obs-timeout",
} as const;

export const QUEUE_TIMEOUT_MS = {
  [QUEUE_NAMES.OCR]: 180000,
  [QUEUE_NAMES.EMBEDDING]: 120000,
  [QUEUE_NAMES.EXTRACTION]: 300000,
  [QUEUE_NAMES.SEMANTIC_CONFLICT]: 60000,
  [QUEUE_NAMES.RENDER_PDF]: 90000,
  [QUEUE_NAMES.PENDING_OBS_TIMEOUT]: 30000,
} as const;

export const THREE_PROCESS_DEPLOYMENT = {
  app_port: 3000,
  pipeline_worker_health_port: 3002,
  pdf_worker_health_port: 3001,
} as const;

import { z } from "zod";

const envSchema = z.object({ DATABASE_URL: z.string().url(), REDIS_URL: z.string().url(), R2_ACCOUNT_ID: z.string().min(1), R2_ACCESS_KEY_ID: z.string().min(1), R2_SECRET_ACCESS_KEY: z.string().min(1), R2_BUCKET_NAME: z.string().min(1), XAI_API_KEY: z.string().min(1), OPENAI_API_KEY: z.string().min(1), PADDLEOCR_TOKEN: z.string().min(1), PADDLEOCR_API_URL: z.string().url(), MEM0_API_KEY: z.string().min(1), NEXTAUTH_URL: z.string().url(), NEXTAUTH_SECRET: z.string().min(32), AUTH_TRUST_HOST: z.coerce.boolean(), PDF_WORKER_URL: z.string().url(), NEXT_PUBLIC_APP_URL: z.string().url() });
const parsed = envSchema.safeParse(process.env);
if (!parsed.success) { const keys = parsed.error.issues.map((i) => i.path.join(".")).filter(Boolean); throw new Error(`Invalid environment configuration. Missing/invalid keys: ${keys.join(", ")}`); }
export const env = parsed.data;

import { drizzle } from "drizzle-orm/node-postgres";
import { Pool } from "pg";
import { env } from "@/lib/env";

const pool = new Pool({ connectionString: env.DATABASE_URL, min: 2, max: 10 });
pool.on("release", (client: any) => { void client.query("RESET app.current_company_id").catch(() => undefined); });

export const db = drizzle(pool);
export { pool };

import { sql } from "drizzle-orm";

export async function withTenant<T>(db: any, companyId: string, callback: (tx: any) => Promise<T>): Promise<T> {
  if (!companyId) throw new Error("withTenant requires a non-empty companyId");
  return db.transaction(async (tx: any) => {
    await tx.execute(sql`SET LOCAL app.current_company_id = ${companyId}`);
    return callback(tx);
  });
}

export * from "./auth";
export * from "./documents";
export * from "./evidence";
export * from "./observations";
export * from "./derivations";
export * from "./conflicts";
export * from "./reports";
