evidenceBlocks.parentBlockId.references(() => evidenceBlocks.blockId, { onDelete: "set null" });

import { pgEnum, pgTable, uuid, text, numeric, date, timestamp, real, index, jsonb } from "drizzle-orm/pg-core";
