import { eq } from "drizzle-orm";

export const { handlers, auth, signIn, signOut } = NextAuth({
  session: { strategy: "jwt", maxAge: 60 * 60 },
  providers: [Credentials({ credentials: { email: { label: "Email", type: "email" }, password: { label: "Password", type: "password" } }, async authorize(credentials) { if (!credentials?.email || !credentials?.password) return null; const [user] = await db.select().from(users).where(eq(users.email, String(credentials.email))).limit(1); if (!user) return null; const ok = await bcrypt.compare(String(credentials.password), user.passwordHash); if (!ok) return null; return { id: user.userId, email: user.email, company_id: user.companyId, role: user.role }; } })],
  callbacks: {
    async jwt({ token, user }) { if (user) { token.sub = user.id as string; token.company_id = (user as any).company_id; token.role = (user as any).role; } return token; },
    async session({ session, token }) { session.user = { ...session.user, user_id: token.sub as string, company_id: token.company_id as string, role: token.role as "admin" | "editor" | "viewer" } as any; return session; }
  }
});

