  created_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT preference_pointer_company_user_client_unique UNIQUE (company_id, user_id, client_id)
);
CREATE UNIQUE INDEX preference_pointer_company_user_null_client_unique_idx ON preference_memory_pointer (company_id, user_id) WHERE client_id IS NULL;
CREATE INDEX preference_pointer_user_idx ON preference_memory_pointer (user_id);

CREATE TABLE chat_session (
  session_id uuid PRIMARY KEY DEFAULT uuid_generate_v7(),
  company_id uuid NOT NULL REFERENCES company(company_id) ON DELETE CASCADE,
  user_id uuid NOT NULL REFERENCES "user"(user_id) ON DELETE CASCADE,
  title text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT chat_session_title_len CHECK (char_length(title) <= 200)
);
CREATE INDEX chat_session_user_created_desc_idx ON chat_session (user_id, created_at DESC);
CREATE INDEX chat_session_company_idx ON chat_session (company_id);
CREATE TRIGGER chat_session_set_updated_at BEFORE UPDATE ON chat_session FOR EACH ROW EXECUTE FUNCTION set_updated_at();

CREATE TABLE chat_message (
  message_id uuid PRIMARY KEY DEFAULT uuid_generate_v7(),
  session_id uuid NOT NULL REFERENCES chat_session(session_id) ON DELETE CASCADE,
  role chat_role NOT NULL,
  type chat_message_type NOT NULL,
  content jsonb NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX chat_message_session_created_asc_idx ON chat_message (session_id, created_at ASC);

CREATE TABLE notification (
  notification_id uuid PRIMARY KEY DEFAULT uuid_generate_v7(),
  company_id uuid NOT NULL REFERENCES company(company_id) ON DELETE CASCADE,
  user_id uuid NULL REFERENCES "user"(user_id) ON DELETE CASCADE,
  type notification_type NOT NULL,
  payload jsonb NOT NULL DEFAULT '{}'::jsonb,
  read boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX notification_unread_partial_idx ON notification (company_id, user_id, read) WHERE read = false;
CREATE INDEX notification_company_created_desc_idx ON notification (company_id, created_at DESC);

CREATE TABLE pending_manual_observation (
  pending_id uuid PRIMARY KEY DEFAULT uuid_generate_v7(),
  company_id uuid NOT NULL REFERENCES company(company_id) ON DELETE CASCADE,
  session_id uuid NOT NULL REFERENCES chat_session(session_id) ON DELETE CASCADE,
  status pending_obs_status NOT NULL DEFAULT 'pending',
  prefilled jsonb NOT NULL DEFAULT '{}'::jsonb,
  created_at timestamptz NOT NULL DEFAULT now(),
  expires_at timestamptz GENERATED ALWAYS AS (created_at + INTERVAL '10 minutes') STORED
);
CREATE INDEX pending_manual_observation_session_idx ON pending_manual_observation (session_id);
CREATE INDEX pending_manual_observation_expiry_pending_partial_idx ON pending_manual_observation (expires_at) WHERE status = 'pending';
CREATE INDEX pending_manual_observation_company_idx ON pending_manual_observation (company_id);

CREATE TABLE audit_log (
  log_id uuid PRIMARY KEY DEFAULT uuid_generate_v7(),
  company_id uuid NOT NULL REFERENCES company(company_id) ON DELETE CASCADE,
  entity_type text NOT NULL,
  entity_id uuid NOT NULL,
  action text NOT NULL,
  actor_id uuid NULL REFERENCES "user"(user_id) ON DELETE SET NULL,
  "timestamp" timestamptz NOT NULL DEFAULT now(),
  metadata jsonb NOT NULL DEFAULT '{}'::jsonb
);
CREATE RULE no_update_audit_log AS ON UPDATE TO audit_log DO INSTEAD NOTHING;
CREATE RULE no_delete_audit_log AS ON DELETE TO audit_log DO INSTEAD NOTHING;
CREATE INDEX audit_log_entity_idx ON audit_log (entity_type, entity_id);
CREATE INDEX audit_log_actor_partial_idx ON audit_log (actor_id) WHERE actor_id IS NOT NULL;
CREATE INDEX audit_log_timestamp_desc_idx ON audit_log ("timestamp" DESC);

